var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 발동, 2시간 경과","JPN":"前兆プロトコル発動より2時間経過","ENG":"2 hours after the Omen Protocol Activation","TWN":"前兆協議啟動，經過2小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 관리국 본부","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>管理局本部","ENG":"Administration Direct-Control City, <color=#ffd34c>Charade</color> Administration HQ","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>管理局本部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……샤레이드의 상황은 이해했어.","JPN":"……シャレードの状況は理解した。","ENG":"...Understood. I have a clear grasp of the situation in Charade.","TWN":"……我明白查雷德目前的狀況了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"시니어의 통제가 없는 가운데도 도시에 나타난 5종 침식체를 섬멸하고.","JPN":"シニアの統制がない中でも都市に現れた第5種侵食体を殲滅。","ENG":"Even without a Senior's oversight, you eliminated a Category 5 C.O. that appeared in the city.","TWN":"在沒有Senior統籌的情況下，仍成功殲滅出現在城市的第5類侵蝕體。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"경보 발령 전에, 주요 지구의 시민 7할을 안전 쉘터로 대피시켰다면서?","JPN":"警報発令前に、主要地区市民の7割を安全シェルターに避難させたそうだな？","ENG":"And before the alarm was issued, you evacuated 70% of the major districts' civilians into safe shelters?","TWN":"而且在警報發布前，就讓主要區域7成的市民撤離至安全避難所，對吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"의외야, 오지만디아스.","JPN":"どうしたんだ、オジマンディアス。","ENG":"That's unexpected, Ozymandias.","TWN":"真讓人意外啊，奧茲曼迪亞斯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트한테 들었던 거랑 달리, 제법 믿음직스럽잖아?","JPN":"リヒャルトに聞いた話と違って、随分頼もしいじゃないか。","ENG":"You're far more reliable than what I heard from Richard.","TWN":"跟我從理查那裡聽到的不一樣，其實還挺可靠的嘛？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드 권한 대행</color>\\n그라운드 원 시니어, 르네 말루프","JPN":"<color=#ffd34c>シャレード権限代行</color>\\nグラウンド・ワンのシニア、ルネ・マルーフ","ENG":"<color=#ffd34c>Charade's Acting Authority</color>\\nGround One Senior, Renée Maalouf","TWN":"<color=#ffd34c>查雷德臨時代理人</color>\\nG1 Senior，芮妮．瑪盧夫"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흥, 하여간 얌전히 칭찬해 주면 어디 덧나?","JPN":"ふん、まったく。素直に褒めることくらいできないの？","ENG":"Hmph. Would it kill you to praise someone properly for once?","TWN":"哼，真是的，就不能好好稱讚一句嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"배배 꼬여지곤. 내가 제때 나서지 않았으면, 샤레이드가 무사했을 것 같아?","JPN":"捻くれてるわね。私が出遅れてたらシャレードは無事じゃすまなかったのよ？","ENG":"If I hadn't stepped in when I did, do you really think Charade would've come out unscathed?","TWN":"老是拐彎抹角的。要不是我及時出手，你覺得查雷德能平安無事嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드</color>\\n공인 S급 카운터, 오지만디아스","JPN":"<color=#ffd34c>シャレード</color>\\n公認S級カウンター、オジマンディアス","ENG":"<color=#ffd34c>Charade</color>\\nOfficial Grade S Counter, Ozymandias","TWN":"<color=#ffd34c>查雷德</color>\\n認證S級制裁者，奧茲曼迪亞斯"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서 전조 현상이라고 했나?","JPN":"それで、前兆現象って言ったっけ？","ENG":"So this is what you're calling an omen phenomenon?","TWN":"所以這就是所謂的前兆現象嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"전 세계 대균열에서도 지금과 비슷한 일이 동시에 일어나고 있다고 했지?","JPN":"全世界の大亀裂でも、同じようなことが同時に起きているんでしょ？","ENG":"You said similar incidents are happening simultaneously at Grand Dimension Crevices all over the world, right?","TWN":"你說過世界各地的大峽谷同時也發生了類似的狀況吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래, 관리국은 현재 최고 등급 재난 경보를 내려둔 상황이야.","JPN":"ああ、管理局は現在、最高ランクの災難警報を発令したところだ。","ENG":"Yes. The Administration has issued the highest-level disaster alert.","TWN":"沒錯。管理局目前已經發布最高等級的災害警報。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"시니어가 부재한 캄파멘토와 챔버 측에서도 이에 걸맞은 대응을 하고 있다고 들었어.","JPN":"シニアが不在中のカンパメントとチェンバー側でも、各状況に合った対応をしていると聞いている。","ENG":"I've also heard that Campamento and Chamber, both lacking Seniors, are responding accordingly.","TWN":"聽說Senior不在的坎帕門托與強巴也正在對此進行應對。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"또한 그라운드 원에서도 샤레이드와 마찬가지로 광신도의 활동이 보고됐지.","JPN":"そしてグラウンド・ワンでもシャレードと同じく、狂信徒の活動が報告された。","ENG":"And reports of cultist activity have come in from Ground One as well, just like in Charade.","TWN":"此外，G1那裡也和查雷德一樣，回報了瘋狂信徒的活動。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 사건의 윤곽이 서서히 잡히고 있는 것 같네.","JPN":"事件のおおまかな形がだんだん見え始めてきたな。","ENG":"It seems the outline of the incident is finally taking shape.","TWN":"看來，整起事件的輪廓逐漸有了眉目。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"말루프 권한 대행, 이러고 있을 때가 아닙니다.","JPN":"マルーフ権限代行、こうしている場合ではありません。","ENG":"Acting Authority Maalouf, now is not the time for this.","TWN":"瑪盧夫臨時代理人，現在不是說這些的時候。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"지금 이 시간에도 대균열은 점점 확장하고 있습니다.","JPN":"この瞬間にも大亀裂は拡張し続けています。","ENG":"Even as we speak, the Grand Dimension Crevice continues to expand.","TWN":"此時此刻大峽谷仍在不斷擴張。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이 속도라면, 머지않아 샤레이드 전역이 대균열에 휩쓸리고 말겠죠.","JPN":"この速度だと、まもなくシャレード全域が大亀裂に呑まれます。","ENG":"At this rate, all of Charade will soon be swallowed by it.","TWN":"照這個速度，用不了多久查雷德全域都會被捲入大峽谷。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>조디악 나이츠</color>\\n블루시프트 단장, 에스테로사 드 슈발리에","JPN":"<color=#ffd34c>ゾディアックナイツ</color>\\nブルーシフト団長、エステロサ・ド・シュヴァリエ","ENG":"<color=#ffd34c>Zodiac Knights</color>\\nBlueshift Captain, Esterosa de Chevalier","TWN":"<color=#ffd34c>十二宮騎士團</color>\\n藍移團長，艾斯特洛索"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조속히 대책을 세워야만 합니다.","JPN":"早急に対策を立てるべきかと。","ENG":"We must establish countermeasures immediately.","TWN":"必須立刻擬定對策。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"많은 시민들이 대피를 마쳤지만, 이 도시에는 시민권이 없는 자들도 있습니다.","JPN":"大部分の市民は避難を終えていますが、この都市には市民権を持たない者もいます。","ENG":"Many civilians have evacuated, but there are also those in this city without citizenship.","TWN":"雖然大多數市民已完成撤離，但不具市民身分的人仍留在這座城市。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"우리 조디악 나이츠는 결코 그들을 외면할 수 없습니다.","JPN":"我々ゾディアックナイツは彼らを見捨てることなどできません。","ENG":"We, the Zodiac Knights, cannot turn our backs on them.","TWN":"我們十二宮騎士團，絕不可能漠視不管。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이의를 제기하죠, 슈발리에 경.","JPN":"異議があります、シュヴァリエ卿。","ENG":"I must raise an objection, Dame Chevalier.","TWN":"我有異議，艾斯特洛索卿。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"아무래도 당신은 무언가 착각하고 있는 모양이군요.","JPN":"どうやらあなたは何か勘違いしているようですね。","ENG":"It seems you are under a misunderstanding.","TWN":"看來你似乎誤會了什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>조니 앤 멜로니</color>\\n대표, 람다 스파타리","JPN":"<color=#ffd34c>ジョニー＆メロニー</color>\\n代表、ラムダ・スパタリー","ENG":"<color=#ffd34c>Jonie & Melonie</color>\\nCEO, Lamda Spatari","TWN":"<color=#ffd34c>強尼＆梅蘭妮</color>\\n代表，蘭達．史派特"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"태스크포스로서 조디악 나이츠는 이곳 샤레이드를 담당 구역으로 두고 있죠.","JPN":"タスクフォースとしてゾディアックナイツはここシャレードを担当しています。","ENG":"As a TASKFORCE, the Zodiac Knights are assigned to Charade as your designated sector.","TWN":"身為特遣勢力，十二宮騎士團的負責區域正是查雷德。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"따라서 재난 상황 발생 시, 담당 구역의 방위를 책임지는 것이 당신들의 의무입니다.","JPN":"よって、災害状況が発生した場合、担当区域の防衛に責任を持つことがあなたたちの義務となります。","ENG":"Therefore, in the event of a disaster, your duty is to defend your assigned area.","TWN":"因此發生災害時，防衛負責的區域是你們的職責。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"시민권조차 부여받지 못한 빈민들을 지키는 것이 아니라.","JPN":"市民権すら与えられていない貧民を守ることではなく。","ENG":"Not to protect impoverished people who lack even citizenship.","TWN":"而不是去保護那些連市民身分都沒有的貧民。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 말은 지금 빈민들을 외면하라는 뜻인가?","JPN":"それはつまり、貧民たちを見捨てろということですか？","ENG":"Are you saying we should abandon the poor?","TWN":"你的意思是，要我們現在對貧民見死不救嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그건 너무하잖아? 돈이 없을 뿐이지, 그 사람들도 사람이라구, 사람!","JPN":"あんまりだよ！　お金がないだけで、彼らも同じ人間なんだよ！","ENG":"That's heartless, isn't it? Just because they're poor doesn't make them any less human!","TWN":"這也太過分了吧？他們只是沒有錢，他們也是人啊，是人！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"사람? 글쎄요, 이 도시에서 그들을 사람이라고 부를 수 있을까요?","JPN":"人間？　さあ。果たして彼らを人間と呼べるのでしょうか？　しかもこの都市を背景にして。","ENG":"Human? Well... can we truly call them human in this city?","TWN":"人？是嗎？在這座城市，真的能稱他們為人嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"はあ？","ENG":"What did you say?!","TWN":"你說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"애초에 인간은 저마다 가치가 다릅니다.","JPN":"そもそも人間の価値はそれぞれです。","ENG":"To begin with, human worth is not equal.","TWN":"每個人的價值原本就不一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신들이 지키고자 하는 이들은 삼등 시민조차 되지 못하는 불법 거주자일 뿐이죠.","JPN":"あなたたちが守ろうとしている者たちは、三等市民にすらなれない不法滞在者に過ぎません。","ENG":"Those you wish to protect are merely illegal residents who do not even qualify as third-grade citizens.","TWN":"你們想要保護的，不過是連三等市民都稱不上的非法居住者而已。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"샤레이드 관리국은 그들을 위해, 방위 서비스를 제공할 의무가 없어요.","JPN":"シャレード管理局は彼らのために防衛サービスを提供する義務はありません。","ENG":"The Charade Administration has no obligation to provide them with defense services.","TWN":"查雷德管理局沒有義務為他們提供防衛服務。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그건……!","JPN":"そ、それは……！","ENG":"Th-That's...!","TWN":"這、這……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"백번양보해서 빈민들을 구한다고 해도, 그들을 어디에 수용하죠?","JPN":"百歩譲って貧民たちを助けたとして、彼らをどこに収容するつもりですか？","ENG":"Even if we were to save the poor, where would you house them?","TWN":"就算退一百步來說，救了那些貧民後，你們打算把他們安置在哪裡？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"관리국에서 제공하는 안전 쉘터는 이 도시의 시민을 위한 것입니다.","JPN":"管理局が提供している安全シェルターは、この都市の市民のために用意されたものです。","ENG":"The Administration's safe shelters are meant for this city's citizens.","TWN":"管理局提供的安全避難所，是為了這座城市的市民。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"성실한 납세자들과 불법 거주자들을 같은 곳에 수용한다는 것은 언어도단이겠죠.","JPN":"誠実な納税者と不法滞在者を同じ場所に収容するなど言語道断。","ENG":"Housing law-abiding taxpayers alongside illegal residents would be absurd.","TWN":"讓守法的納稅人與非法居住者待在同一空間，實在是荒謬至極。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그리고 당신들의 책무는, 이 도시의 시민들을 지키는 것.","JPN":"そしてあなたたちの責務はこの都市の市民たちを守ること。","ENG":"And your responsibility is to protect this city's citizens.","TWN":"而你們的職責，是守護這座城市的市民。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그렇지 않습니까, 슈발리에 경?","JPN":"違いますか？　シュヴァリエ卿。","ENG":"Is that not correct, Dame Chevalier?","TWN":"不是嗎，艾斯特洛索卿？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"확실히…….","JPN":"確かに……","ENG":"I see...","TWN":"的確……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대의 말은 논리적으로 옳아.","JPN":"君の主張は論理的に正しい。","ENG":"Your argument is logically sound.","TWN":"你的言論在邏輯上是正確的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"다, 단장님……!","JPN":"だ、団長……！","ENG":"C-Captain...!","TWN":"團、團長……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 거절하지.","JPN":"だが、断る。","ENG":"However, I refuse.","TWN":"我拒絕。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"구할 사람을 가리는 것은 우리 조디악 나이츠의 기사도와는 맞지 않아.","JPN":"助ける人を区別するのは、我々ゾディアックナイツの騎士道に反する。","ENG":"Choosing who deserves saving runs counter to the chivalry of the Zodiac Knights.","TWN":"區分誰該被拯救這一點，不符合我們十二宮騎士團的騎士信條。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"손을 내미는 것이 빈자든, 부자든…….","JPN":"手を差し伸べるのが貧しい者であれ、裕福な者であれ……","ENG":"Whether the hand reaching out belongs to the poor or the wealthy...","TWN":"不論是貧是富……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"누군가가 도움을 청한다면, 우리는 그자의 손을 잡을 의무가 있어.","JPN":"誰かが助けを求めているなら、我々はその手を取る義務がある。","ENG":"If someone asks for help, we are duty-bound to take their hand.","TWN":"只要有人伸手求援，我們就有義務握住那隻手。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"어리석군요, 슈발리에 경. 사회를 지키는 것은 개인이 아니라, 시스템입니다.","JPN":"愚かですね、シュヴァリエ卿。社会を守るのは個人ではなくシステムです。","ENG":"How foolish, Dame Chevalier. Society is upheld not by individuals, but by systems.","TWN":"真是愚蠢啊，艾斯特洛索卿。守護社會的從來不是個人，而是系統。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그 주장은 허울 좋은 이상론일 뿐, 광대 놀음과 다를 바 없겠죠.","JPN":"あなたの主張は綺麗事の理想論、道化師の遊びに過ぎません。","ENG":"That claim is nothing more than lofty idealism. Mere clownery.","TWN":"你的主張不過是虛有其表的理想，和空頭支票沒什麼兩樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"후훗, 광대 놀음이라…….","JPN":"ふふっ、道化師の遊びか……","ENG":"Haha, clownery...?","TWN":"呵，空頭支票嗎……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대가 말하는 시스템이라는 것조차 인간이 만든 것. 완벽하지 않아.","JPN":"君の言うシステムとやらも所詮人間が作ったものだ。完璧ではない。","ENG":"Even the system you speak of was created by humans, and thus imperfect.","TWN":"就連你口中的系統也是人類創造的，那並不完美。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 사람을 구하려는 우리의 기사도가 광대 놀음라고 한다면…….","JPN":"その上で、人を助けようとする我々の騎士道が道化師の遊びというのなら……","ENG":"So if saving people is to be called clownery...","TWN":"所以，如果拯救他人的騎士信條，被稱為開空頭支票的話……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"우리는 기꺼이 광대가 되어주겠다.","JPN":"我々は喜んで道化師になってみせよう。","ENG":"Then we shall gladly become clowns.","TWN":"那我們甘願成為小丑。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"훗, 소문대로 외골수로군.","JPN":"ふっ、噂通り頑固な人だ。","ENG":"Hmph. As stubborn as the rumors say.","TWN":"哼，果然跟傳聞一樣是個死腦筋。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 이야기가 헛돌고 있잖아.","JPN":"待て、話が空回りしているじゃないか。","ENG":"Enough. This discussion is going nowhere.","TWN":"等等，現在完全離題了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"두 사람, 진정 좀 하지? 당신들은 S급 카운터, 이 도시의 최고 전력들이라고!","JPN":"二人とも落ち着け。あなたたちはS級カウンター、この都市の最高戦力なんだぞ！","ENG":"Both of you, calm down. You're Grade S Counters, the city's greatest assets!","TWN":"能不能冷靜一點？你們兩個可是S級制裁者，是這座城市最強的戰力！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스, 네가 좀 중재해야 하는 거 아니야?","JPN":"オジマンディアス、ちょっとは仲裁したらどうだ？","ENG":"Ozymandias, shouldn't you be mediating this?","TWN":"奧茲曼迪亞斯，你不出面仲裁嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 왜?","JPN":"なんで私が？","ENG":"Why should I?","TWN":"我為什麼要？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이대로 싸움 구경하는 것도 재밌을 거 같은데?","JPN":"このまま喧嘩を見物するのも面白そうじゃない。","ENG":"Watching this turn into a fight sounds entertaining enough.","TWN":"就這樣看你們吵架，似乎也挺有趣的啊？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"크윽, 정말이지 죄다 도움이 안 되네.","JPN":"くっ、どいつもこいつも役に立たない……！","ENG":"Kgh. Honestly, none of you are any help at all.","TWN":"嘖，真的是沒一個靠得住。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그보다, 당신들… 성황청은 어쩔 셈이야?","JPN":"それより、あなたたち……聖皇庁はどうするつもりだ？","ENG":"More importantly, what about you two? What do you plan to do about the Holy Curia?","TWN":"比起這個，你們……聖皇廳打算怎麼辦？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"수배범을 놓쳤으니, 시국으로 돌아가는 게 우선인가?","JPN":"手配犯を逃したわけだし、まずは聖皇庁へ帰還か？","ENG":"Since the fugitive escaped, shouldn't you return to the Holy Curia first?","TWN":"既然讓通緝犯逃走了，是不是該先回到時局？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청?</color>\\n집행 사제?, 루시아 릿지","JPN":"<color=#ffd34c>聖皇庁？</color>\\n執行司祭？、ルシア・リッジ","ENG":"<color=#ffd34c>Holy Curia?</color>\\nInquisitor?, Lucia Ridge","TWN":"<color=#ffd34c>聖皇廳？</color>\\n執行司祭？，露西卡．李奇"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"성황청은 개뿔! 어쩌다가 일이 이렇게 된 거지?","JPN":"聖皇庁なんて知るか！　どうしてこうなったんだ？","ENG":"Holy Curia, my foot! How did things even end up like this?","TWN":"聖皇廳個鬼啊！事情怎麼會變成這樣？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"치, 침착하자, 루시아. 여기서 한 마디라도 실수했다간 바로 나가리야.","JPN":"お、落ち着こう、ルシア。ここで口を滑らしたら即アウトだ。","ENG":"Calm down, Lucia. One wrong word here and it's all over.","TWN":"冷靜點，露西卡。現在只要說錯一句話就完了。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저 법학부장에게 목이 잘리든지…….","JPN":"あの法学部長に首を飛ばされるか……","ENG":"Either that Dean of Law will have my head...","TWN":"不是被那個法學院院長斬首……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"관리국에 수배당해 평생 안절부절못하면서 살든지…….","JPN":"管理局に手配されて一生隠れて生きるか……","ENG":"Or I'll be wanted by the Administration for the rest of my life...","TWN":"就是被管理局通緝，一輩子提心吊膽活著……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"둘 중 하나… 아니, 둘 다 될 수도 있다고……!","JPN":"どっちか……いや、どっちもあるかもしれない……！","ENG":"One or the other... No, maybe both...!","TWN":"兩個中選一個……不對，搞不好兩個一起來……！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"펴, 평소처럼 하는 거야! 이런 일은 익숙하잖아?","JPN":"い、いつも通りにやるんだ！　こういうの何度も経験してきたじゃん！","ENG":"J-just act like you always do! You're used to this kind of thing, right?","TWN":"照、照平常那樣處理！我們不是已經很熟練了嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지금 분위기에서 우리 종교학부가 택해야 하는 최선의 선택지는……!","JPN":"今の流れで私たち宗教学部が選ぶべき最善の選択肢は……！","ENG":"Given the current atmosphere, the best choice for the Religion Department is...!","TWN":"在現在這種氣氛下，我們宗教學院能選擇的最佳方案是……！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"주께서는 늘 말씀하셨죠.","JPN":"主はいつもおっしゃいます。","ENG":"The Lord has always said so.","TWN":"主曾說過，"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네 이웃을 네 몸과 같이 사랑하라…….","JPN":"あなたの隣人をあなた自身のように愛せよ……","ENG":"Love your neighbor as yourself...","TWN":"要愛人如己……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"오늘 그 말씀의 의미를 슈발리에 경의 발언을 통해 다시금 깨닫게 되었습니다.","JPN":"今日シュヴァリエ卿の発言を聞き、その言葉の意味に改めて気づかされました。","ENG":"Today, through Dame Chevalier's words, I have come to understand that teaching anew.","TWN":"今天透過艾斯特洛索卿的發言，我再次體悟了這句話的意義。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"수, 수녀님?","JPN":"し、シスター？","ENG":"S-Sister?","TWN":"修、修女？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"불량식품, 갑자기 무슨 뚱딴지 같은 소리예요?","JPN":"お菓子さん、急にどうしたんですか？","ENG":"Hey, junk food. What kind of nonsense are you suddenly spouting?","TWN":"垃圾食物，你突然在說什麼鬼話啊？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"쉿. 다 생각이 있다고.","JPN":"しーっ、黙って聞いてなさい。","ENG":"Shh. I have a plan.","TWN":"噓，我自有打算。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"비록, 성황청이 집행 사제들에게 부여한 소임은 시국의 방위일지도 모릅니다.","JPN":"聖皇庁が執行司祭たちに与えた役目は聖皇庁の防衛かもしれません。","ENG":"Though the duty granted to the Inquisitors by the Holy Curia may be the defense of the Holy Curia itself.","TWN":"即便聖皇廳賦予執行司祭的使命，是守護時局。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그렇다고 이 도시에 긍휼한 자들을 외면하는 것 또한 주님께서 바라지 않으시겠죠.","JPN":"だからといってこの都市の貧しい者たちを見捨てるなど、主は望まれないはずです。","ENG":"Turning away from the pitiful souls of this city is surely not what the Lord desires.","TWN":"但我想主也不會希望，我們對這座城市需要憐憫之人視而不見。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저희도 전력을 보태어, 이 도시를 수호하도록 하겠습니다.","JPN":"私たちも戦力として加勢し、この都市を守ります。","ENG":"We, too, shall lend our strength to protect this city.","TWN":"我們也將全力協助，共同守護這座城市。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 성황청의 협조에 관리국도 감사를 표하지.","JPN":"わかった。聖皇庁の協力に、管理局からも感謝の意を表する。","ENG":"Very well. The Administration thanks the Holy Curia for its cooperation.","TWN":"很好，管理局對聖皇廳的協助表示感謝。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"재난이 끝나고 상황이 안정된다면, 이 건에 대해 관리국 차원의 사례를 약속할게.","JPN":"災害が収束し状況が安定してきたら、この件については管理局から謝礼をすると約束しよう。","ENG":"Once the disaster is over and stability is restored, I promise official compensation.","TWN":"等災難結束、情勢穩定後，我會以管理局的名義給予相應的謝禮。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사, 사례라고…? 얼마? 얼마나……!?","JPN":"しゃ、謝礼……？　いくら？　いくらぐらい……！？","ENG":"C-compensation...? How much? How much are we talking?!","TWN":"謝、謝禮……？多少？有多少……！？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이래서야 촌극이 따로 없군요.","JPN":"とんだ茶番ですわ。","ENG":"What a farce.","TWN":"這簡直是場鬧劇。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리가 긴급히 기관에 협조 요청을 구하길래 기꺼이 응했건만…….","JPN":"古い声が機関に緊急協力要請を送ったというから応じてみたものの……","ENG":"The Old Voice urgently requested the Institution's cooperation, and I obliged...","TWN":"明明是老聲音緊急請求機構協助，我才答應的……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관</color>\\n기관장, 엘리자베스 팬드래건","JPN":"<color=#ffd34c>プリドウェン機関</color>\\n機関長、エリザベス・ペンドラゴン","ENG":"<color=#ffd34c>Prydwen Institution</color>\\nChief, Elizabeth Pendragon","TWN":"<color=#ffd34c>普利多溫機關</color>\\n機關長，伊莉莎白．潘德拉貢"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 아가씨…! 각 조직을 대표하는 자들이 모인 자리입니다……!","JPN":"お、お嬢様……！　各組織の代表が集まる席ですよ……！","ENG":"L-Lady Elizabeth...! Representatives of every organization are present...!","TWN":"小、小姐……！這裡可是各組織代表齊聚的場合……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서요? 이 웃기지도 않은 탁상공론을 더 지켜보자고요?","JPN":"それがどうしたというのです？　この笑えない机上の空論をこのまま見ているつもりですか？","ENG":"So what? Shall we continue indulging in this ridiculous armchair debate?","TWN":"所以呢？要我繼續旁觀這種無聊的紙上談兵嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"시간이 없으니, 결론만 말씀드리죠.","JPN":"時間がありません。結論だけお話しましょう。","ENG":"There's no time. I'll be brief.","TWN":"時間不多，我就直說結論了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전조 현상이란 것은 일단 한 번 시작된 이상, 막을 수 없습니다.","JPN":"前兆現象は一度始まった以上、止めることはできません。","ENG":"Once an omen phenomenon has begun, it cannot be stopped.","TWN":"所謂的前兆現象一旦開始，就無法阻止。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 도시에 도착하기로 한, 선로전환기라는 장치 역시 현상을 지연시킬 뿐.","JPN":"この都市に届く予定の線路転換器も、現象の進行を遅らせるだけ。","ENG":"The Track Switcher scheduled to arrive in this city will only delay the phenomenon.","TWN":"抵達這座城市的線路轉換器裝置，也只能延緩現象而已。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"원인을 해결하는 근본적인 대책이라고는 할 수 없어요.","JPN":"原因を解決する根本的な対策にはなり得ません。","ENG":"It is by no means a fundamental solution that addresses the cause.","TWN":"不能說是解決根本原因的對策。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"무엇보다도 세계가 절체절명의 위기에 빠진 지금.","JPN":"何より、世界が絶体絶命の危機にさらされている今。","ENG":"More importantly, with the world facing an unprecedented crisis...","TWN":"更何況是在世界陷入存亡危機的此刻。"},"stage":{"bg":"PRYDWEN_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 절호의 순간을 교단, <color=#ffd34c>얄다바오트의 자녀들</color>이 놓칠 리가 없겠죠.","JPN":"この絶好のチャンスを教団……<color=#ffd34c>ヤルダバオトの子供</color>が見逃すはずがありません。","ENG":"The cult, <color=#ffd34c>Children of Yaldabaoth</color>, will not let this moment pass.","TWN":"教團<color=#ffd34c>亞達巴沃的子女</color>，不可能錯過如此絕妙的時機。"},"stage":{"bg":"PRYDWEN_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"틀림없이 이 상황에 개입하려 할 겁니다.","JPN":"彼らは間違いなくこの状況に介入しようとしてくるはずです。","ENG":"They will certainly attempt to intervene.","TWN":"他們必然會介入。"},"stage":{"bg":"PRYDWEN_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 어쩌면 이 상황 자체가 교단이 개입한 결과일지도 모르죠.","JPN":"いいえ、もしかしたらこの状況こそ、教団が介入した結果かもしれませんね。","ENG":"In fact, this very situation may already be the result of their interference.","TWN":"不，說不定這個狀況就是教團介入的結果。"},"stage":{"bg":"PRYDWEN_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……그러니 람다 스파타리.","JPN":"……ですから、ラムダ・スパタリー。","ENG":"...Therefore, Lamda Spatari.","TWN":"……所以，蘭達．史派特。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신의 <color=#ffd34c>친구</color>분께 전하세요.","JPN":"あなたの<color=#ffd34c>お友達</color>に伝えてください。","ENG":"Deliver this message to your <color=#ffd34c>friend</color>.","TWN":"請你轉告你的<color=#ffd34c>朋友</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"노블레스 오블리주. 자신이 마땅히 해야 할 의무를 방관하지 말라고.","JPN":"ノブレス・オブリージュ。己のなすべき義務を傍観するなと。","ENG":"Noblesse oblige. Do not stand idly by when duty calls.","TWN":"貴族，不要對自己理應承擔的責任袖手旁觀。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"글쎄, 확답은 못 하겠군.","JPN":"さあね、確答はできない。","ENG":"I cannot promise anything.","TWN":"我給不了你什麼肯定的答覆。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기대는 안 합니다. 전하기만 하면 됐어요.","JPN":"そもそも期待していません。伝えるだけでよいのです。","ENG":"I don't expect you to. Delivering the message is enough.","TWN":"我本來就沒期待，只要你傳話就夠了。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"가죠, 라이언.","JPN":"行きましょう、ライアン。","ENG":"Let's go, Ryan.","TWN":"走吧，萊恩。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금까지 이름 없이 사라져간 모든 기관원들이 그랬듯이…….","JPN":"今まで名もなく散っていったすべての機関員がそうだったように……","ENG":"Just as all unnamed agents who vanished before us did...","TWN":"就如同那些至今消逝的所有無名機構成員一樣……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금의 우리에게 승산이 있든 없든, 기관은 기관의 의무를 다하는 겁니다.","JPN":"今の私たちに勝ち目があろうがなかろうが、機関は機関の義務を果たします。","ENG":"Whether victory is possible or not, the Institution will fulfill its duty.","TWN":"不論現在的我們是否擁有勝算，機關都將履行機關的義務。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"의무라, 하여간 기관도 피곤하다니까~","JPN":"義務ね～まったく、機関も面倒くさいんだから～","ENG":"Duty, huh? Honestly, the Institution never gets a break...","TWN":"義務啊，機構也真夠累人的～"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"하지만 승산 없는 도박은 역시 따분하지 않아?","JPN":"でもやっぱり、勝ち目のない賭け事ってつまらなくない？","ENG":"But isn't a gamble with no odds just boring?","TWN":"不過沒有勝算的賭局，不是反而更有趣嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"어때, 기관장님?","JPN":"どう？　機関長。","ENG":"Well, what do you say, Chief?","TWN":"怎麼樣，機關長？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"나랑 손잡으면, 적어도 5% 정도는 승산을 올려 줄 수 있다고?","JPN":"私と手を組めば、少なくとも5％ぐらいは勝率を上げてあげられるわよ？","ENG":"If you join hands with me, I could raise your odds by at least 5%.","TWN":"只要和我聯手，至少能把勝率提高5%喔？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>에크하르트 초월지식 학회</color>\\n종교학부장, 아그네스 아비게일","JPN":"<color=#ffd34c>エクハルト超越知識学会</color>\\n宗教学部長、アグネス・アビゲイル","ENG":"<color=#ffd34c>Eckhart's Society for Preternatural Research (ESPR)</color>\\nDean of Religion, Agnes Abigail","TWN":"<color=#ffd34c>埃克哈特超越知識學會</color>\\n宗教學院院長，艾格妮絲．亞比該"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"아비게일……?","JPN":"アビゲイル……？","ENG":"Abigail...?","TWN":"亞比該……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아그네스 언니?","JPN":"アグネスお姉さま？","ENG":"Agnes?","TWN":"艾格妮絲姊姊？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니가 어째서……?","JPN":"姉さんがどうして……？","ENG":"What are you doing here...?","TWN":"姊姊怎麼會……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"어째서라니, 이거 섭섭한 걸~?","JPN":"どうしてって、寂しいこと言うわね～","ENG":"Why am I here? That's kind of hurtful...","TWN":"什麼怎麼會？真令人傷心耶～？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그야, 우리 귀염둥이들을 도우러 온 게 당연하잖아?","JPN":"かわい子ちゃんたちを助けに来たに決まってるじゃない。","ENG":"Of course I came to help my little darlings.","TWN":"我當然是來幫我們的小可愛啊？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CITY_CHARADE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};